UPDATE securities_holdings
SET quantity = quantity + #{quantityDelta},
    total_buy_amount = total_buy_amount + #{buyAmountDelta},
    avg_buy_price = #{avgBuyPrice}
WHERE id = #{id}

UPDATE securities_holdings
SET quantity = quantity - #{quantityDelta},
    total_buy_amount = #{totalBuyAmountAfter},
    avg_buy_price = #{avgBuyPriceAfter}
WHERE id = #{id}
  AND quantity - reserved_quantity >= #{quantityDelta}

UPDATE securities_holdings
SET quantity = #{quantity},
    avg_buy_price = #{avgBuyPrice},
    total_buy_amount = #{totalBuyAmount}
WHERE id = #{id}

UPDATE securities_holdings
SET quantity = #{quantity},
    avg_buy_price = #{avgBuyPrice},
    total_buy_amount = #{totalBuyAmount}
WHERE id = #{id}

UPDATE securities_holdings
SET reserved_quantity = reserved_quantity + #{quantity}
WHERE id = #{id}
  AND quantity - reserved_quantity >= #{quantity}

UPDATE securities_holdings
SET reserved_quantity = reserved_quantity - #{quantity}
WHERE id = #{id}
  AND reserved_quantity >= #{quantity}

UPDATE securities_holdings
SET quantity = #{quantityAfter},
    reserved_quantity = #{reservedQuantityAfter},
    avg_buy_price = #{avgBuyPriceAfter},
    total_buy_amount = #{totalBuyAmountAfter}
WHERE id = #{id}
  AND quantity >= #{quantity}
  AND reserved_quantity >= #{quantity}
